        "_sort_publish_date":1524686760,
        "_sort_start":1525024800,
        "create_date":"2018-04-25T13:06:00-07:00",
        "description":"<p>Join us for a cup of coffee, snack, and a read through the Sunday Times at our terrazzo bar.\n</p>\n<p>All are welcome, sharing news is encouraged!\n</p>",
        "end":"2018-04-29T14:00:00-07:00",
