        "_sort_publish_date":1527711240,
        "_sort_start":1528048800,
        "create_date":"2018-05-30T13:14:00-07:00",
        "description":"<p>Come by every Sunday for a browse through the New York & Los Angeles Times, a cup of coffee, and some food!\n</p>\n<p>We have been collectively finishing the crossword each week, but need all the help we can get—stop by!\n</p>",
        "end":"2018-06-03T14:00:00-07:00",
