        "_sort_end":1527991200,
        "_sort_last_updated":1527804540,
        "_sort_publish_date":1527785520,
        "_sort_start":1527973200,
        "create_date":"2018-05-31T09:52:00-07:00",
        "description":"<p>All gender vintage military clothing pop-up with designer and stylist Elise Bader!\n</p>\n<p><a href=\"https://www.instagram.com/halt_la/\">H.A.L.T.</a> is an endless collection of vintage military pieces. Bringing the previously discarded new life. Join us for drinks and fun!\n</p>",
        "end":"2018-06-02T19:00:00-07:00",
        "isDraft":false,
