        "_sort_publish_date":1529883600,
        "_sort_start":1530468000,
        "create_date":"2018-06-24T16:40:00-07:00",
        "description":"<p>Continuing the weekly tradition, come read the New York and Los Angeles Times over a cup of coffee and snack.  Clever with clues?  Help us with the crossword!\n</p>\n<p><em>All are welcome!</em>\n</p>",
        "end":"2018-07-01T14:00:00-07:00",
