        "_sort_start":1536516000,
        "create_date":"2018-08-22T09:27:00-07:00",
        "description":"<p>Drop by, browse the Sunday newspapers, and work on the crosswords with us.\n</p>\n<p>Complimentary coffee and brunchy treats.\n</p>\n<p><em>All are welcome!</em><br>\n</p>",
