        "last_updated":"2018-10-10T09:09:00-07:00",
        "name":"Sunday Gathering Times",
        "preview_url":"eb212a0b-4c39-db8a-8978-a27530c3b7da",
        "publish_date":"2018-10-10T09:09:00-07:00",
        "start":"2018-10-14T11:00:00-07:00",
