        "last_updated":"2018-10-16T09:19:00-07:00",
        "name":"Sunday Gathering ",
        "preview_url":"66274c80-ae1f-cf36-f822-f380e1b77e32",
        "publish_date":"2018-10-16T09:19:00-07:00",
        "start":"2018-10-21T11:00:00-07:00",
