        "last_updated":"2018-12-04T12:11:00-08:00",
        "name":"Loving Others: Community Support",
        "preview_url":"67cf2676-863c-9695-0735-ba3fb3a91e36",
        "publish_date":"2018-11-21T09:42:00-08:00",
        "start":"2018-12-10T19:30:00-08:00",
